public void captureArgumentsFrom(Invocation invocation) {
        if (invocation.getMethod().isVarArgs()) {
            int indexOfVararg = invocation.getRawArguments().length - 1;

            // Fix the loop from going past index of varargs because it should not go over the boundary
            for (int position = 0; position <= indexOfVararg && position < matchers.size(); position++) {
                Matcher m = matchers.get(position);

                // Addition check to see if the matcher implements CapturesArguments before trying to capture arguments
                if (m instanceof CapturesArguments) {
                    ((CapturesArguments) m).captureFrom(invocation.getRawArguments()[position]);
                }
            }

            for (int position = indexOfVararg + 1; position < matchers.size(); position++) {
                Matcher m = matchers.get(position);

                // Addition check to see if the matcher implements CapturesArguments before trying to capture arguments
                if (m instanceof CapturesArguments) {
                    ((CapturesArguments) m).captureFrom(invocation.getArgumentAt(position, Object.class));
